//! P4 physics-as-admission — gate inferred kinematics against green gnosis-math laws.
//!
//! third-eye runs NO force solver. Each kinematic fact a track asserts is admitted only if it
//! satisfies the corresponding *proven* law. These functions are the ENFORCEMENT point — the
//! predicates the cited Lean theorems prove; the proofs live in gnosis-math, third-eye applies
//! them at the edge (the same split as `aeon-3d/src/admission-gate.ts`: TS/Rust enforces, Lean
//! proves). Verdicts mirror the admission gate: accept / abstain / decline.
//!
//! Laws pinned (all green, Init-only, zero-axiom):
//! - causality / lightspeed: `AckermannLightConeBridge.lean:133` `certified_iff_in_lightcone`,
//!   `:183` `subluminal_never_reaches_front` — a velocity above the scene's causal-cone ceiling
//!   is not physical motion (it's an association error), so DECLINE it.
//! - gravity / settling: `VacuumIsOnlyForce.lean:85` `vacuum_force_contracts` — "at rest" is only
//!   admissible when speed is monotonically contracting toward rest; jitter at low speed ABSTAINS.
//! - energy / order: `InformationConservation.lean:337` `information_conservation` — order (our
//!   confidence that an object is real) cannot exceed the chaos spent to resolve it (observation
//!   evidence). Unevidenced certainty ABSTAINS; there is no free trajectory.

use crate::track::Track;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Verdict {
    Accept,
    Abstain,
    Decline,
}

impl Verdict {
    pub fn as_str(self) -> &'static str {
        match self {
            Verdict::Accept => "accept",
            Verdict::Abstain => "abstain",
            Verdict::Decline => "decline",
        }
    }
}

/// A single admitted/withheld claim about a track, with the law it was judged under.
#[derive(Debug, Clone)]
pub struct FactVerdict {
    pub fact: &'static str,
    pub verdict: Verdict,
    pub law: &'static str,
    pub reason: String,
}

#[derive(Debug, Clone)]
pub struct PhysicsConfig {
    /// Causal-cone ceiling: max admissible speed in normalised units / second. A real object in
    /// frame-normalised coords cannot traverse the frame in one tick; jumps above this are
    /// association errors, declined under the lightcone law.
    pub c_max: f32,
    /// Below this speed a track is a candidate for "at rest".
    pub rest_speed: f32,
    /// Confidence (hits/(hits+misses)) required to admit existence as known.
    pub min_confidence: f32,
    /// Window (trajectory points) for the rest-contraction check.
    pub rest_window: usize,
}

impl Default for PhysicsConfig {
    fn default() -> Self {
        PhysicsConfig {
            c_max: 1.5,
            rest_speed: 0.02,
            min_confidence: 0.6,
            rest_window: 6,
        }
    }
}

/// The admitted physical state of a track after gating.
#[derive(Debug, Clone)]
pub struct AdmittedState {
    pub id: u64,
    /// Net verdict: the most restrictive across all checks (decline > abstain > accept).
    pub verdict: Verdict,
    pub facts: Vec<FactVerdict>,
    pub confidence: f32,
    pub at_rest: bool,
}

fn confidence(t: &Track) -> f32 {
    let denom = (t.hits + t.misses).max(1) as f32;
    t.hits as f32 / denom
}

/// Is the speed monotonically contracting toward rest over the recent window? (vacuum_force).
fn speed_contracting(t: &Track, window: usize) -> bool {
    let n = t.trajectory.len();
    if n < window + 1 {
        return false;
    }
    let mut prev_speed = f32::INFINITY;
    let mut ok = true;
    for k in (n - window)..n {
        let (t1, x1, y1) = t.trajectory[k];
        let (t0, x0, y0) = t.trajectory[k - 1];
        let dt = (t1 - t0).max(1e-3) as f32;
        let s = (((x1 - x0).powi(2) + (y1 - y0).powi(2)).sqrt()) / dt;
        // Allow tiny noise; require non-increasing (within slack).
        if s > prev_speed + 0.005 {
            ok = false;
            break;
        }
        prev_speed = s;
    }
    ok
}

/// Gate a track's kinematics. Returns the admitted state with per-law verdicts.
pub fn admit(t: &Track, cfg: &PhysicsConfig) -> AdmittedState {
    let mut facts = Vec::new();

    // 1. Lightcone / speed-of-light bound.
    let speed = t.speed();
    let v_verdict = if speed > cfg.c_max {
        Verdict::Decline
    } else {
        Verdict::Accept
    };
    facts.push(FactVerdict {
        fact: "velocity_causal",
        verdict: v_verdict,
        law: "AckermannLightConeBridge.subluminal_never_reaches_front",
        reason: format!("|v|={:.3} vs c_max={:.3}", speed, cfg.c_max),
    });

    // 2. Existence / order backed by evidence (information_conservation).
    let conf = confidence(t);
    let exist_verdict = if t.confirmed && conf >= cfg.min_confidence {
        Verdict::Accept
    } else {
        Verdict::Abstain
    };
    facts.push(FactVerdict {
        fact: "exists_known",
        verdict: exist_verdict,
        law: "InformationConservation.information_conservation",
        reason: format!("confidence={:.2} (hits {} misses {})", conf, t.hits, t.misses),
    });

    // 3. At-rest only if speed is low AND monotonically contracting (vacuum_force_contracts).
    let mut at_rest = false;
    if speed < cfg.rest_speed {
        if speed_contracting(t, cfg.rest_window) {
            at_rest = true;
            facts.push(FactVerdict {
                fact: "at_rest",
                verdict: Verdict::Accept,
                law: "VacuumIsOnlyForce.vacuum_force_contracts",
                reason: format!("|v|={:.3} contracting over {} pts", speed, cfg.rest_window),
            });
        } else {
            facts.push(FactVerdict {
                fact: "at_rest",
                verdict: Verdict::Abstain,
                law: "VacuumIsOnlyForce.vacuum_force_contracts",
                reason: format!("|v|={:.3} low but not contracting (jitter)", speed),
            });
        }
    }

    // Net verdict = most restrictive.
    let net = if facts.iter().any(|f| f.verdict == Verdict::Decline) {
        Verdict::Decline
    } else if facts
        .iter()
        .any(|f| f.fact == "exists_known" && f.verdict == Verdict::Abstain)
    {
        // If we can't even certify existence, the whole object is abstain.
        Verdict::Abstain
    } else {
        Verdict::Accept
    };

    AdmittedState {
        id: t.id,
        verdict: net,
        facts,
        confidence: conf,
        at_rest,
    }
}
